class Solution:
    def maximumAmount(self, coins):
        m, n = len(coins), len(coins[0])
        best = float('-inf')
        paths = []

        def dfs(i, j, path):
            path.append((i, j))
            if i == m - 1 and j == n - 1:
                paths.append(list(path))
            else:
                if i + 1 < m:
                    dfs(i + 1, j, path)
                if j + 1 < n:
                    dfs(i, j + 1, path)
            path.pop()

        dfs(0, 0, [])
        for path in paths:
            vals = [coins[i][j] for i, j in path]
            L = len(vals)
            import itertools
            for r in range(0, min(2, L) + 1):
                for combo in itertools.combinations(range(L), r):
                    s = sum(0 if idx in combo else vals[idx] for idx in range(L))
                    best = max(best, s)
        return best

