class Solution:
    def maximumAmount(self, coins):
        m, n = len(coins), len(coins[0])
        NEG = float('-inf')
        dp = [[[NEG] * 3 for _ in range(n)] for _ in range(m)]
        for i in range(m):
            for j in range(n):
                val = coins[i][j]
                if i == 0 and j == 0:
                    dp[i][j][0] = val
                    dp[i][j][1] = 0
                    dp[i][j][2] = NEG
                    continue
                for t in range(3):
                    best = NEG
                    if i > 0 and dp[i - 1][j][t] > NEG:
                        best = max(best, dp[i - 1][j][t] + val)
                    if j > 0 and dp[i][j - 1][t] > NEG:
                        best = max(best, dp[i][j - 1][t] + val)
                    if t >= 1:
                        if i > 0 and dp[i - 1][j][t - 1] > NEG:
                            best = max(best, dp[i - 1][j][t - 1])
                        if j > 0 and dp[i][j - 1][t - 1] > NEG:
                            best = max(best, dp[i][j - 1][t - 1])
                    dp[i][j][t] = best
        return max(dp[m - 1][n - 1])

