var maximumAmount = function(coins) {
    const m = coins.length, n = coins[0].length;
    const NEG = -Infinity;
    const dp = Array.from({ length: m }, () => Array.from({ length: n }, () => [NEG, NEG, NEG]));
    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            const val = coins[i][j];
            if (i === 0 && j === 0) {
                dp[i][j][0] = val;
                dp[i][j][1] = 0;
                dp[i][j][2] = NEG;
                continue;
            }
            for (let t = 0; t < 3; t++) {
                let best = NEG;
                if (i > 0 && dp[i - 1][j][t] > NEG) best = Math.max(best, dp[i - 1][j][t] + val);
                if (j > 0 && dp[i][j - 1][t] > NEG) best = Math.max(best, dp[i][j - 1][t] + val);
                if (t >= 1) {
                    if (i > 0 && dp[i - 1][j][t - 1] > NEG) best = Math.max(best, dp[i - 1][j][t - 1]);
                    if (j > 0 && dp[i][j - 1][t - 1] > NEG) best = Math.max(best, dp[i][j - 1][t - 1]);
                }
                dp[i][j][t] = best;
            }
        }
    }
    return Math.max(...dp[m - 1][n - 1]);
};
